    });
  });
});

import {
  Controller,
  Get,
  Post,
  Req,
  Body,
  UseGuards,
  Query,
} from '@nestjs/common';
import { ConfigService } from '@nestjs/config';
import { AuthService } from './auth.service';
import { AuthGuard } from '@nestjs/passport';
import { LoginDto } from './schemas/login.schema';
import { RegisterDto } from './schemas/register.schema';
import { OnboardingDto } from './schemas/onboarding.schema';
import {
  ActivateMfaDto,
  VerifyMfaDto,
  VerifyMfaRecoveryDto,
} from './schemas/mfa.schema';
import {
  RequestPasswordResetDto,
  ResetPasswordDto,
} from './schemas/password-reset.schema';
import { Throttle, SkipThrottle } from '@nestjs/throttler';
import { GithubLinkGuard } from './guards/github.link.guard';
import { GoogleLinkGuard } from './guards/google.link.guard';
import { VerifiedAuth } from '../../shared/decorators/verified.decorator';
import { ApiTags, ApiOperation } from '@nestjs/swagger';
import {
  VerifyEmailDto,
  OAuthCallbackQueryDto,
} from './schemas/auth-contract.dto';

@ApiTags('Auth')
@Throttle({ default: { limit: 5, ttl: 60000 } })
@Controller('auth')
export class AuthController {
  constructor(
    private readonly authService: AuthService,
    private config: ConfigService,
  ) {}

  @Post('login')
  login(@Body() dto: LoginDto) {
    return this.authService.login(dto);
  }

  @Post('register')
  register(@Body() dto: RegisterDto) {
    return this.authService.register(dto);
  }

  @UseGuards(AuthGuard('refresh'))
  @Post('refresh')
  refresh(@Req() req: any) {
    return this.authService.refresh(req.user);
  }

  @Throttle({ default: { limit: 3, ttl: 3600000 } })
  @Post('password-reset/request')
  requestPasswordReset(@Body() dto: RequestPasswordResetDto) {
    return this.authService.requestPasswordReset(dto);
  }

  @Post('password-reset/reset')
  resetPassword(@Body() dto: ResetPasswordDto) {
    return this.authService.resetPassword(dto);
  }

  @VerifiedAuth()
  @Post('logout')
  logout(@Req() req: any) {
    return this.authService.logout(req.user);
  }

  @Post('onboarding')
  completeOnboarding(@Body() dto: OnboardingDto, @Req() req: any) {
    // The onboarding token is in the Authorization header.
    return this.authService.completeOnboarding(dto, req.headers.authorization);
  }

  // --- OAuth Login ---

  @UseGuards(AuthGuard('github'))
  @Post('github')
  githubLogin() {}

  @UseGuards(AuthGuard('google'))
  @Post('google')
  googleLogin() {}

  @UseGuards(AuthGuard('github'))
  @Get('github/callback')
  @SkipThrottle()
  githubCallback(@Req() req: any) {
    return this.authService.oauthLogin(req.user, 'GITHUB');
  }

  @UseGuards(AuthGuard('google'))
  @Get('google/callback')
  @SkipThrottle()
  googleCallback(@Req() req: any) {
    return this.authService.oauthLogin(req.user, 'GOOGLE');
  }

  // --- Secure Account Linking ---

  @VerifiedAuth()
  @Get('github/link')
  async linkGithub(@Req() req: any) {
    return this.authService.githubLink(req.user.id);
  }

  @VerifiedAuth()
  @Get('google/link')
  async linkGoogle(@Req() req: any) {
    return this.authService.googleLink(req.user.id);
  }

  @VerifiedAuth()
  @UseGuards(GithubLinkGuard)
  @Get('github/link/callback')
  @SkipThrottle()
  async linkGithubCallback(
    @Req() req: any,
    @Query() query: OAuthCallbackQueryDto,
  ) {
    return this.authService.linkOAuth(
      req.authUser.id,
      req.user,
      'GITHUB',
      query.state,
    );
  }

  @VerifiedAuth()
  @UseGuards(GoogleLinkGuard)
  @Get('google/link/callback')
  @SkipThrottle()
  async linkGoogleCallback(
    @Req() req: any,
    @Query() query: OAuthCallbackQueryDto,
  ) {
    return this.authService.linkOAuth(
      req.authUser.id,
      req.user,
      'GOOGLE',
      query.state,
    );
  }

  // --- Email Verification ---

  @Post('verify-email')
  verifyEmail(@Body() dto: VerifyEmailDto) {
    return this.authService.verifyEmail(dto.code);
  }

  // --- MFA ---

  @VerifiedAuth()
  @Get('mfa/setup')
  setupMfa(@Req() req: any) {
    return this.authService.setupMfa(req.user.id);
  }

  @VerifiedAuth()
  @Post('mfa/activate')
  activateMfa(@Req() req: any, @Body() dto: ActivateMfaDto) {
    return this.authService.activateMfa(req.user.id, dto.code);
  }

  @Post('mfa/verify')
  verifyMfa(@Body() dto: VerifyMfaDto) {
    return this.authService.verifyMfa(dto.userId, dto.code, dto.mfaToken);
  }

  @Post('mfa/verify-recovery')
  verifyMfaRecovery(@Body() dto: VerifyMfaRecoveryDto) {
    return this.authService.verifyMfaRecovery(
      dto.userId,
      dto.backupCode,
      dto.mfaToken,
    );
  }
}

import { INestApplication } from '@nestjs/common';
import { AuthService } from './auth.service';
import { resetBefore, resetAfter } from '../../../test/shared';
import { App } from 'supertest/types';
import Redis from 'ioredis';

jest.mock(
  'otplib',
  () => {
    return {
      TOTP: jest.fn().mockImplementation(() => ({
        generate: jest.fn().mockReturnValue('123456'),
        verify: jest.fn().mockReturnValue(true),
        generateSecret: jest.fn().mockReturnValue('mock_secret'),
        keyuri: jest.fn().mockReturnValue('otp_uri'),
      })),
      NobleCryptoPlugin: jest.fn(),
      ScureBase32Plugin: jest.fn(),
    };
  },
  { virtual: true },
);

describe('AuthService (Integration)', () => {
  let app: INestApplication<App>;
  let service: AuthService;
  let redis: Redis;
  let testId: string;

  beforeEach(async () => {
    const setup = await resetBefore();
    app = setup.app;
    testId = setup.id;
    service = app.get(AuthService);
    redis = app.get('REDIS');
  });

  afterEach(async () => {
    await resetAfter(app);
  });

  describe('Registration & Constraints', () => {
    it('should prevent duplicate email registration', async () => {
      const dto = {
        email: `dup-${testId}@example.com`,
        username: `user1-${testId}`,
        password: 'Password123!',
        role: 'CANDIDATE',
      };

      await service.register(dto);

      // Attempting same email
      await expect(
        service.register({ ...dto, username: `user2-${testId}` }),
      ).rejects.toThrow('Email already exists');
    });

    it('should prevent duplicate username registration', async () => {
      const dto = {
        email: `user1-${testId}@example.com`,
        username: `dup-${testId}`,
        password: 'Password123!',
        role: 'CANDIDATE',
      };

      await service.register(dto);

      // Attempting same username
      await expect(
        service.register({ ...dto, email: `user2-${testId}@example.com` }),
      ).rejects.toThrow('Username already exists');
    });
  });

  describe('MFA Integration', () => {
    it('should store encrypted MFA secret in DB and decrypt correctly', async () => {
      // 1. Register and verify email
      const email = `mfa-${testId}@example.com`;
      await service.register({
        email,
        password: 'Password123!',
        role: 'CANDIDATE',
      });
      const user = await (service as any).prisma.user.findUnique({
        where: { email },
      });
      await (service as any).prisma.user.update({
        where: { id: user.id },
        data: { isEmailVerified: true } as any,
      });

      // 2. Setup MFA
      const { secret } = await service.setupMfa(user.id);
      expect(secret).toBeDefined();

      // 3. Activate MFA (uses the secret from Redis)
      // Since it's integration, we can't easily generate a real TOTP code without otplib helper
      const authenticator = (service as any).getAuthenticator();
      const code = authenticator.generate(secret);

      await service.activateMfa(user.id, code);

      // 4. Verify DB state - secret should be encrypted
      const updatedUser = await (service as any).prisma.user.findUnique({
        where: { id: user.id },
      });
      expect(updatedUser.mfaEnabled).toBe(true);
      expect(updatedUser.mfaSecret).toContain(':'); // IV:TAG:ENC format
      expect(updatedUser.mfaSecret).not.toEqual(secret);
    });
  });

  describe('Password Reset & Session Invalidation', () => {
    it('should manage password reset tokens in Redis', async () => {
      const email = `reset-${testId}@example.com`;
      await service.register({
        email,
        username: `reset-${testId}`,
        password: 'Password123!',
        role: 'CANDIDATE',
      });

      await service.requestPasswordReset({ email });

      // Check Redis for token (we have to find it since it's random)
      const keys = await redis.keys('password_reset:*');
      expect(keys.length).toBe(1);

      const token = keys[0].split(':')[1];
      const ttl = await redis.ttl(keys[0]);
      expect(ttl).toBeGreaterThan(3500); // Close to 1h

      // Reset password
      await service.resetPassword({ token, newPassword: 'NewPassword123!' });

      // Token should be deleted
      const exists = await redis.exists(keys[0]);
      expect(exists).toBe(0);
    });

    it('should invalidate all sessions on password reset', async () => {
      const email = `inv-${testId}@example.com`;
      await service.register({
        email,
        password: 'Password123!',
        role: 'CANDIDATE',
      });
      const user = await (service as any).prisma.user.findUnique({
        where: { email },
      });
      await (service as any).prisma.user.update({
        where: { id: user.id },
        data: { isEmailVerified: true } as any,
      });

      // 1. Initial Login to get tokens
      const loginResult = await service.login({
        identifier: email,
        password: 'Password123!',
      });
      expect(await redis.exists(`refresh:${user.id}`)).toBe(1);

      // 2. Reset password
      const token = 'fake-token';
      await redis.set(`password_reset:${token}`, user.id);
      await service.resetPassword({ token, newPassword: 'NewPassword123!' });

      // 3. Session should be gone
      expect(await redis.exists(`refresh:${user.id}`)).toBe(0);
    });
  });
});

import {
  Injectable,
  UnauthorizedException,
  Inject,
  ConflictException,
  BadRequestException,
  Logger,
} from '@nestjs/common';
import { JwtService } from '@nestjs/jwt';
import { PrismaService } from '../../prisma/prisma.service';
import { ConfigService } from '@nestjs/config';
import Redis from 'ioredis';
import * as bcrypt from 'bcrypt';
import * as crypto from 'crypto';
import { encrypt, decrypt } from '../../shared/crypto.utils';
import * as QRCode from 'qrcode';

import { InjectQueue } from '@nestjs/bullmq';
import { Queue } from 'bullmq';

type Provider = 'LOCAL' | 'GITHUB' | 'GOOGLE';

@Injectable()
export class AuthService {
  constructor(
    private prisma: PrismaService,
    private jwt: JwtService,
    private config: ConfigService,
    @Inject('REDIS') private readonly redis: Redis,
    @InjectQueue('email') private readonly emailQueue: Queue,
  ) {}

  private readonly logger = new Logger(AuthService.name);

  private async checkRateLimit(identifier: string) {
    const key = `rl_login:${identifier}`;
    const attempts = await this.redis.incr(key);
    if (attempts === 1) {
      await this.redis.expire(key, 900); // 15 mins block
    }
    if (attempts > 5) {
      this.logger.warn(`LOGIN_FAILURE: Rate limit exceeded for ${identifier}`);
      throw new UnauthorizedException(
        'Too many login attempts. Please try again later.',
      );
    }
  }

  private async resetRateLimit(identifier: string) {
    await this.redis.del(`rl_login:${identifier}`);
  }

  private getAuthenticator() {
    // Dynamic require to handle ESM/CJS compatibility in test environments
    const otplib = require('otplib');
    const { TOTP, NobleCryptoPlugin, ScureBase32Plugin } = otplib.TOTP
      ? otplib
      : otplib.default || {};

    if (!TOTP) {
      throw new Error(
        `Failed to load otplib components. Available keys: ${Object.keys(otplib)}`,
      );
    }

    return new TOTP({
      crypto: new NobleCryptoPlugin(),
      base32: new ScureBase32Plugin(),
    });
  }

  private getEncryptionKey(): string {
    const key = this.config.get<string>('AUTH_ENCRYPTION_KEY');
    if (!key)
      throw new Error('AUTH_ENCRYPTION_KEY is not defined in environment');
    return key;
  }

  async register(dto: any) {
    try {
      const hash = await bcrypt.hash(dto.password, 10);

      const user = await this.prisma.user.create({
        data: {
          email: dto.email,
          username: dto.username,
          isEmailVerified: false,
          authAccounts: {
            create: {
              provider: 'LOCAL',
              providerId: dto.email,
              passwordHash: hash,
            },
          },
        } as any,
      });

      this.logger.log(
        `REGISTRATION_SUCCESS: User ${user.email} registered locally`,
      );
      await this.initiateEmailVerification(user.id, user.email!);
      return this.handleLoginResponse(user);
    } catch (error) {
      if (error.code === 'P2002') {
        const target = error.meta?.target?.[0];
        throw new ConflictException(
          `${target ? target.charAt(0).toUpperCase() + target.slice(1) : 'Account'} already exists`,
        );
      }
      throw error;
    }
  }

  async login(dto: any) {
    await this.checkRateLimit(dto.identifier);

    const user = await this.prisma.user.findFirst({
      where: {
        OR: [{ email: dto.identifier }, { username: dto.identifier }],
      },
      include: { authAccounts: true },
    });

    if (!user) throw new UnauthorizedException('Invalid credentials');

    const account = user.authAccounts.find((a) => a.provider === 'LOCAL');
    if (!account || !account.passwordHash)
      throw new UnauthorizedException('Invalid credentials');

    const isValid = await bcrypt.compare(dto.password, account.passwordHash);
    if (!isValid) {
      this.logger.warn(
        `LOGIN_FAILURE: Invalid credentials for ${dto.identifier}`,
      );
      throw new UnauthorizedException('Invalid credentials');
    }

    await this.resetRateLimit(dto.identifier);
    this.logger.log(`LOGIN_SUCCESS: User ${user.email} logged in locally`);

    return this.handleLoginResponse(user);
  }

  private async handleLoginResponse(user: any) {
    if (!user.isEmailVerified) {
      return { needsVerification: true, email: user.email };
    }

    if (user.mfaEnabled) {
      const mfaToken = this.jwt.sign(
        { sub: user.id, type: 'mfa', jti: crypto.randomUUID() },
        {
          secret: this.config.get('jwt_secret.mfa'),
          expiresIn: '5m',
        },
      );
      return { mfaRequired: true, mfaToken };
    }

    return await this.issueTokens(user.id, user.isEmailVerified);
  }

  async verifyMfa(userId: string, code: string, mfaToken: string) {
    try {
      const payload: any = this.jwt.verify(mfaToken, {
        secret: this.config.get('jwt_secret.mfa'),
      });
      if (payload.sub !== userId || payload.type !== 'mfa')
        throw new UnauthorizedException();
    } catch {
      throw new UnauthorizedException('Invalid MFA session');
    }

    const user = await this.prisma.user.findUnique({ where: { id: userId } });
    if (!user || !(user as any).mfaSecret) throw new UnauthorizedException();

    const secret = decrypt((user as any).mfaSecret, this.getEncryptionKey());
    const isValid = this.getAuthenticator().verify({ token: code, secret });
    if (!isValid) throw new UnauthorizedException('Invalid MFA code');

    return await this.issueTokens(user.id, (user as any).isEmailVerified);
  }

  async refresh(user: any) {
    const userId = user.id;
    const storedJti = await this.redis.get(`refresh:${userId}`);
    const decodedJti = this.jwt.decode(user.refreshToken)?.jti;

    if (!storedJti || storedJti !== decodedJti) {
      if (storedJti) {
        // Token reuse detected. Hijack scenario! Revoke all sessions.
        await this.redis.del(`refresh:${userId}`);
        this.logger.warn(
          `MFA_BYPASS_ATTEMPT / TOKEN REUSE DETECTED: Revoked sessions for user ${userId}`,
        );
      }
      throw new UnauthorizedException('Invalid or expired refresh token');
    }

    const dbUser = await this.prisma.user.findUnique({ where: { id: userId } });
    if (!dbUser) throw new UnauthorizedException('User not found');

    return await this.issueTokens(userId, (dbUser as any).isEmailVerified);
  }

  async logout(user: any) {
    await this.redis.del(`refresh:${user.id}`);
    return { message: 'Logged out' };
  }

  private async issueTokens(userId: string, isEmailVerified: boolean) {
    const user = await this.prisma.user.findUnique({ where: { id: userId } });
    if (!user) throw new UnauthorizedException('User not found');

    const accessToken = this.jwt.sign(
      {
        sub: userId,
        isEmailVerified,
        role: user.role,
        jti: crypto.randomUUID(),
      },
      {
        secret: this.config.get('jwt_secret.access'),
        expiresIn: '15m',
      },
    );
    const refreshJti = crypto.randomUUID();
    const refreshToken = this.jwt.sign(
      { sub: userId, jti: refreshJti },
      {
        secret: this.config.get('jwt_secret.refresh'),
        expiresIn: '7d',
      },
    );
    await this.redis.set(
      `refresh:${userId}`,
      refreshJti,
      'EX',
      60 * 60 * 24 * 7,
    );
    return { accessToken, refreshToken };
  }

  // --- OAuth & Linking ---

  async oauthLogin(profile: any, provider: Provider) {
    if (!profile) throw new UnauthorizedException();

    const account = await this.prisma.authAccount.findUnique({
      where: { provider_providerId: { provider, providerId: profile.id } },
      include: { user: true },
    });

    if (account) return this.handleLoginResponse(account.user);

    const user = await this.prisma.user.findUnique({
      where: { email: profile.email },
      include: { authAccounts: true },
    });

    if (user) {
      // SECURITY: Only auto-link if BOTH the local account AND the OAuth provider affirm verification.
      if (!user.isEmailVerified) {
        this.logger.warn(
          `LINKING_FAILURE: Attempted auto-link to unverified local account ${user.email}`,
        );
        throw new UnauthorizedException(
          'Email is already registered but not verified. Please verify locally first.',
        );
      }

      if (profile.email_verified === false) {
        this.logger.warn(
          `LINKING_FAILURE: OAuth provider ${provider} email not verified for ${profile.email}`,
        );
        throw new UnauthorizedException(
          'OAuth email not verified. Please verify your social account or log in locally.',
        );
      }

      const existingAccount = user.authAccounts.find(
        (a) => a.provider === provider,
      );
      if (!existingAccount) {
        await this.prisma.authAccount.create({
          data: { userId: user.id, provider, providerId: profile.id },
        });
        this.logger.log(
          `ACCOUNT_LINKED: User ${user.id} auto-linked to ${provider}`,
        );
      }
      return this.handleLoginResponse(user);
    }

    const claimId = crypto.randomBytes(32).toString('hex');
    await this.redis.set(
      `onboarding_claim:${claimId}`,
      JSON.stringify({
        provider,
        providerId: profile.id,
        email: profile.email,
        firstName: profile.firstName,
        lastName: profile.lastName,
      }),
      'EX',
      900,
    );

    const tempToken = this.jwt.sign(
      {
        claimId,
        type: 'onboarding',
        jti: crypto.randomUUID(),
      },
      {
        secret: this.config.get('jwt_secret.onboarding'),
        expiresIn: '15m',
      },
    );
    return { needsOnboarding: true, tempToken };
  }

  async generateLinkState(userId: string): Promise<string> {
    const state = crypto.randomBytes(16).toString('hex');
    await this.redis.set(`link_state:${state}`, userId, 'EX', 300);
    return state;
  }

  async linkOAuth(
    userId: string,
    profile: any,
    provider: Provider,
    state: string,
  ) {
    const storedUserId = await this.redis.get(`link_state:${state}`);
    if (!storedUserId || storedUserId !== userId)
      throw new UnauthorizedException('Invalid link state');
    await this.redis.del(`link_state:${state}`);

    const existing = await this.prisma.authAccount.findUnique({
      where: { provider_providerId: { provider, providerId: profile.id } },
    });
    if (existing) throw new ConflictException('Account already linked');

    await this.prisma.authAccount.create({
      data: { userId, provider, providerId: profile.id },
    });

    this.logger.log(
      `ACCOUNT_LINKED: User ${userId} successfully linked ${provider}`,
    );

    return { message: `${provider} linked successfully` };
  }

  async completeOnboarding(dto: any, authHeader: string) {
    if (!authHeader) throw new UnauthorizedException();
    const token = authHeader.split(' ')[1];

    let payload: any;
    try {
      payload = this.jwt.verify(token, {
        secret: this.config.get('jwt_secret.onboarding'),
      });
    } catch {
      throw new UnauthorizedException('Invalid token');
    }
    if (payload.type !== 'onboarding') throw new UnauthorizedException();

    const raw = await this.redis.get(`onboarding_claim:${payload.claimId}`);
    if (!raw) throw new UnauthorizedException('Session expired');
    const oauth = JSON.parse(raw);

    const usernameExists = await this.prisma.user.findUnique({
      where: { username: dto.username },
    });
    if (usernameExists) throw new ConflictException('Username taken');

    try {
      const user = await this.prisma.user.create({
        data: {
          email: oauth.email,
          username: dto.username,
          firstName: oauth.firstName,
          lastName: oauth.lastName,
          isEmailVerified: true,
          authAccounts: {
            create: {
              provider: oauth.provider as Provider,
              providerId: oauth.providerId as string,
            },
          },
        } as any,
      });

      await this.redis.del(`onboarding_claim:${payload.claimId}`);

      this.logger.log(
        `LOGIN_SUCCESS: User ${user.email} logged in via OAuth (Onboarding Complete)`,
      );

      return this.handleLoginResponse(user);
    } catch (error) {
      if (error.code === 'P2002') {
        throw new ConflictException('Username or email already taken');
      }
      throw error;
    }
  }

  // --- Email Verification ---

  async initiateEmailVerification(userId: string, email: string) {
    const code = Math.floor(100000 + Math.random() * 900000).toString();
    await this.redis.set(`verify_email:${code}`, userId, 'EX', 3600);

    await this.emailQueue.add('send-verification', {
      to: email,
      subject: 'Verify your Colosseum account',
      html: `<p>Your verification code is: <b>${code}</b></p>`,
    });
  }

  async verifyEmail(code: string) {
    const userId = await this.redis.get(`verify_email:${code}`);
    if (!userId) throw new BadRequestException('Invalid code');

    await this.prisma.user.update({
      where: { id: userId },
      data: { isEmailVerified: true } as any,
    });
    await this.redis.del(`verify_email:${code}`);
    return { message: 'Verified' };
  }

  // --- MFA Setup ---

  async setupMfa(userId: string) {
    const auth = this.getAuthenticator();
    const secret = auth.generateSecret();
    const otpauthUrl = auth.keyuri(userId, 'Colosseeum', secret);
    const qrCode = await QRCode.toDataURL(otpauthUrl);

    await this.redis.set(`mfa_setup:${userId}`, secret, 'EX', 300);
    return { qrCode, secret };
  }

  async activateMfa(userId: string, code: string) {
    const secret = await this.redis.get(`mfa_setup:${userId}`);
    if (!secret) throw new BadRequestException('MFA session expired');

    const isValid = this.getAuthenticator().verify({ token: code, secret });
    if (!isValid) throw new BadRequestException('Invalid MFA code');

    const encryptedSecret = encrypt(secret, this.getEncryptionKey());
    const backupCodes = Array.from({ length: 10 }, () =>
      crypto.randomBytes(4).toString('hex'),
    );
    const encryptedBackupCodes = backupCodes.map((c) =>
      encrypt(c, this.getEncryptionKey()),
    );

    await this.prisma.user.update({
      where: { id: userId },
      data: {
        mfaEnabled: true,
        mfaSecret: encryptedSecret,
        mfaBackupCodes: encryptedBackupCodes,
      } as any,
    });
    await this.redis.del(`mfa_setup:${userId}`);
    return { message: 'MFA activated', backupCodes };
  }

  async verifyMfaRecovery(
    userId: string,
    backupCode: string,
    mfaToken: string,
  ) {
    try {
      const payload: any = this.jwt.verify(mfaToken, {
        secret: this.config.get('jwt_secret.mfa'),
      });
      if (payload.sub !== userId || payload.type !== 'mfa')
        throw new UnauthorizedException();
    } catch {
      throw new UnauthorizedException('Invalid MFA session');
    }

    const user = await this.prisma.user.findUnique({ where: { id: userId } });
    if (
      !user ||
      !(user as any).mfaEnabled ||
      !(user as any).mfaBackupCodes.length
    )
      throw new UnauthorizedException();

    const encryptionKey = this.getEncryptionKey();
    const decryptedCodes = (user as any).mfaBackupCodes.map((c: string) =>
      decrypt(c, encryptionKey),
    );

    const codeIndex = decryptedCodes.indexOf(backupCode);
    if (codeIndex === -1)
      throw new UnauthorizedException('Invalid backup code');

    // Use-once: remove the code
    const updatedCodes = [...(user as any).mfaBackupCodes];
    updatedCodes.splice(codeIndex, 1);

    await this.prisma.user.update({
      where: { id: userId },
      data: { mfaBackupCodes: updatedCodes } as any,
    });

    return await this.issueTokens(user.id, (user as any).isEmailVerified);
  }

  // --- Password Reset ---

  async requestPasswordReset(dto: any) {
    const user = await this.prisma.user.findUnique({
      where: { email: dto.email },
    });

    // SECURITY: Always return success to prevent email enumeration
    if (!user) {
      this.logger.warn(`RESET_REQUEST: Non-existent email ${dto.email}`);
      return {
        message:
          'If an account with that email exists, a reset link has been sent.',
      };
    }

    const token = crypto.randomBytes(32).toString('hex');
    await this.redis.set(`password_reset:${token}`, user.id, 'EX', 3600); // 1 hour

    await this.emailQueue.add('send-reset', {
      to: user.email,
      subject: 'Reset your Colosseum password',
      html: `<p>Click <a href="${this.config.get('app.url')}/reset-password?token=${token}">here</a> to reset your password.</p>`,
    });

    return {
      message:
        'If an account with that email exists, a reset link has been sent.',
    };
  }

  async resetPassword(dto: any) {
    const userId = await this.redis.get(`password_reset:${dto.token}`);
    if (!userId) {
      throw new UnauthorizedException('Invalid or expired reset token');
    }

    const hash = await bcrypt.hash(dto.newPassword, 10);

    await this.prisma.$transaction([
      this.prisma.user.update({
        where: { id: userId },
        data: {
          authAccounts: {
            updateMany: {
              where: { provider: 'LOCAL' },
              data: { passwordHash: hash },
            },
          },
        },
      }),
    ]);

    await this.redis.del(`password_reset:${dto.token}`);
    await this.redis.del(`refresh:${userId}`); // Global logout/session invalidation

    this.logger.log(
      `PASSWORD_RESET_SUCCESS: User ${userId} reset their password`,
    );

    return { message: 'Password reset successfully' };
  }

  async githubLink(userId) {
    const state = await this.generateLinkState(userId);
    const base =
      this.config.get('github.authorizationURL') ||
      'https://github.com/login/oauth/authorize';
    const clientId = this.config.get('github.clientID');
    const redirectUri = `${this.config.get('app.url')}${this.config.get('auth.githubLinkCallback')}`;

    return {
      url: `${base}?client_id=${clientId}&redirect_uri=${redirectUri}&state=${state}&scope=user:email`,
    };
  }

  async googleLink(userId) {
    const state = await this.generateLinkState(userId);
    // Google linking would follow similar pattern
    return { state, message: 'Redirect to Google OAuth with this state' };
  }
}

import { Injectable } from '@nestjs/common';
import { PassportStrategy } from '@nestjs/passport';
import { Strategy } from 'passport-github2';
import { ConfigService } from '@nestjs/config';

@Injectable()
export class GithubStrategy extends PassportStrategy(Strategy, 'github') {
  constructor(private config: ConfigService) {
    super({
      clientID: process.env.GITHUB_CLIENT_ID,
      clientSecret: process.env.GITHUB_CLIENT_SECRET,
      callbackURL: config.get('app.url') + config.get('auth.githubCallback'),
      scope: ['user:email'],
      passReqToCallback: true,
    });
  }

  async validate(accessToken: string, refreshToken: string, profile: any) {
    // GitHub primary email is usually verified if it's the primary one,
    // but we check the profile emails array if available.
    const emailObj =
      profile.emails?.find((e: any) => e.primary) || profile.emails?.[0];

    return {
      githubId: profile.id,
      username: profile.username,
      email: emailObj?.value,
      email_verified: emailObj?.verified ?? true, // GitHub verified status
      accessToken,
    };
  }
}

import { Injectable } from '@nestjs/common';
import { PassportStrategy } from '@nestjs/passport';
import { Strategy } from 'passport-google-oauth20';
import { ConfigService } from '@nestjs/config';

@Injectable()
export class GoogleStrategy extends PassportStrategy(Strategy, 'google') {
  constructor(private config: ConfigService) {
    super({
      clientID: process.env.GOOGLE_CLIENT_ID,
      clientSecret: process.env.GOOGLE_CLIENT_SECRET,
      callbackURL: config.get('app.url') + config.get('auth.googleCallback'),
      scope: ['email', 'profile'],
      passReqToCallback: true,
    });
  }

  async validate(accessToken: string, refreshToken: string, profile: any) {
    return {
      id: profile.id,
      email: profile.emails?.[0]?.value,
      email_verified:
        profile.emails?.[0]?.verified || profile._json?.email_verified,
      username: profile.displayName,
      firstName: profile.name?.givenName,
      lastName: profile.name?.familyName,
    };
  }
}

import { Injectable } from '@nestjs/common';
import { PassportStrategy } from '@nestjs/passport';
import { Strategy, ExtractJwt } from 'passport-jwt';

@Injectable()
export class JwtStrategy extends PassportStrategy(Strategy, 'jwt') {
  constructor() {
    const secret = process.env.JWT_ACCESS_SECRET;

    if (!secret) throw new Error('JWT_SECRET missing');

    super({
      jwtFromRequest: ExtractJwt.fromAuthHeaderAsBearerToken(),
      secretOrKey: secret,
    });
  }

  async validate(payload: any) {
    return {
      id: payload.sub,
      isEmailVerified: payload.isEmailVerified,
      role: payload.role,
    };
  }
}

import { Injectable } from '@nestjs/common';
import { PassportStrategy } from '@nestjs/passport';
import { Strategy, ExtractJwt } from 'passport-jwt';

@Injectable()
export class RefreshStrategy extends PassportStrategy(Strategy, 'refresh') {
  constructor() {
    super({
      jwtFromRequest: ExtractJwt.fromAuthHeaderAsBearerToken(),
      secretOrKey: process.env.JWT_REFRESH_SECRET,
      passReqToCallback: true,
    });
  }

  async validate(req: any, payload: any) {
    const refreshToken = req.get('Authorization').replace('Bearer', '').trim();
    return { id: payload.sub, refreshToken };
  }
}

