        { feePayer: 'payer3', blockTime: Date.now() / 1000 },
        { feePayer: 'payer4', blockTime: Date.now() / 1000 },
        { feePayer: 'payer5', blockTime: Date.now() / 1000 },
      ];
      connectionInstance.getSignaturesForAddress.mockResolvedValue(mockSigs);

      const traction = await service.fetchProgramTraction(
        'mock-program',
        connectionInstance,
      );
      expect(traction.uniqueCallers).toBe(5);
    });

    it('4. sigs with duplicate feePayer -> uniqueCallers deduplicated', async () => {
      const mockSigs = [
        { feePayer: 'payer1', blockTime: Date.now() / 1000 },
        { feePayer: 'payer1', blockTime: Date.now() / 1000 },
        { feePayer: 'payer1', blockTime: Date.now() / 1000 },
      ];
      connectionInstance.getSignaturesForAddress.mockResolvedValue(mockSigs);

      const traction = await service.fetchProgramTraction(
        'mock-program',
        connectionInstance,
      );
      expect(traction.uniqueCallers).toBe(1);
    });

    it('5. sig.blockTime = now - 30 days -> isActive: true', async () => {
      const thirtyDaysAgo = Date.now() / 1000 - 30 * 24 * 60 * 60;
      const mockSigs = [{ feePayer: 'payer1', blockTime: thirtyDaysAgo }];
      connectionInstance.getSignaturesForAddress.mockResolvedValue(mockSigs);

      const traction = await service.fetchProgramTraction(
        'mock-program',
        connectionInstance,
      );
      expect(traction.isActive).toBe(true);
    });

    it('6. sig.blockTime = now - 100 days -> isActive: false', async () => {
      const hundredDaysAgo = Date.now() / 1000 - 100 * 24 * 60 * 60;
      const mockSigs = [{ feePayer: 'payer1', blockTime: hundredDaysAgo }];
      connectionInstance.getSignaturesForAddress.mockResolvedValue(mockSigs);

      const traction = await service.fetchProgramTraction(
        'mock-program',
        connectionInstance,
      );
      expect(traction.isActive).toBe(false);
    });

    it('7. throws -> { uniqueCallers:0, isActive:false, deployedAt:null }', async () => {
      connectionInstance.getSignaturesForAddress.mockRejectedValue(
        new Error('RPC Error'),
      );
      const traction = await service.fetchProgramTraction(
        'mock-program',
        connectionInstance,
      );
      expect(traction).toEqual({
        uniqueCallers: 0,
        isActive: false,
        deployedAt: null,
      });
    });

    it('8. feePayer is null in some sigs -> those sigs skipped from Set', async () => {
      const mockSigs = [
        { feePayer: 'payer1', blockTime: Date.now() / 1000 },
        { feePayer: null, blockTime: Date.now() / 1000 },
        { feePayer: undefined, blockTime: Date.now() / 1000 },
        { blockTime: Date.now() / 1000 }, // No feePayer property
      ];
      connectionInstance.getSignaturesForAddress.mockResolvedValue(mockSigs);

      const traction = await service.fetchProgramTraction(
        'mock-program',
        connectionInstance,
      );
      expect(traction.uniqueCallers).toBe(1); // Only payer1
    });
  });
});

import { Injectable, Inject, Logger } from '@nestjs/common';
import { ConfigService } from '@nestjs/config';
import Redis from 'ioredis';
import { Connection, PublicKey } from '@solana/web3.js';
import { AchievementWhitelistService } from './achievement-whitelist.service';

export interface Achievement {
  type: 'hackathon_win' | 'bounty_completion';
  source: 'colosseum' | 'superteam';
  label: string;
  year: number;
}

export interface ProgramInfo {
  programId: string;
  deployedAt: string | null;
  isActive: boolean;
  uniqueCallers: number;
}

@Injectable()
export class SolanaAdapterService {
  private readonly logger = new Logger(SolanaAdapterService.name);

  private readonly BPF_LOADER = new PublicKey(
    'BPFLoaderUpgradeab1e11111111111111111111111',
  );
  private readonly AUTHORITY_OFFSET = 13;

  constructor(
    private readonly config: ConfigService,
    @Inject('REDIS') private readonly redis: Redis,
    private readonly achievementWhitelist: AchievementWhitelistService,
  ) {}

  async fetchProgramsByAuthority(
    walletAddress: string,
  ): Promise<ProgramInfo[]> {
    const cacheKey = `solana:programs:${walletAddress}`;

    try {
      const cached = await this.redis.get(cacheKey);
      if (cached) {
        return JSON.parse(cached);
      }
    } catch (e) {
      // Ignore cache check errors
    }

    try {
      const solanaRpcUrl = this.config.get<string>('SOLANA_RPC_URL');
      if (!solanaRpcUrl) {
        this.logger.warn('SOLANA_RPC_URL is not configured');
        return [];
      }

      const connection = new Connection(solanaRpcUrl);

      const accounts = await connection.getProgramAccounts(this.BPF_LOADER, {
        filters: [
          { memcmp: { offset: this.AUTHORITY_OFFSET, bytes: walletAddress } },
        ],
      });

      const programs: ProgramInfo[] = [];
      for (const account of accounts) {
        const programId = account.pubkey.toBase58();
        const traction = await this.fetchProgramTraction(programId, connection);
        programs.push({
          programId,
          ...traction,
        });
      }

      try {
        await this.redis.set(cacheKey, JSON.stringify(programs), 'EX', 604800);
      } catch (e) {
        // Ignore cache setting errors
      }

      return programs;
    } catch (err) {
      this.logger.warn({ walletAddress, err }, 'solana_rpc_fail');
      return []; // never throw, graceful degradation
    }
  }

  async fetchProgramTraction(
    programId: string,
    connection: Connection,
  ): Promise<{
    uniqueCallers: number;
    isActive: boolean;
    deployedAt: string | null;
  }> {
    try {
      const sigs = await connection.getSignaturesForAddress(
        new PublicKey(programId),
        { limit: 500 },
      );
      const uniqueCallers = new Set(
        sigs.filter((s: any) => s.feePayer).map((s: any) => s.feePayer),
      ).size;
      const isActive = sigs.some(
        (s) => s.blockTime && s.blockTime > Date.now() / 1000 - 7776000,
      );
      const deployedAt =
        sigs.length && sigs[sigs.length - 1].blockTime
          ? new Date(sigs[sigs.length - 1].blockTime! * 1000).toISOString()
          : null;
      return { uniqueCallers, isActive, deployedAt };
    } catch (err) {
      this.logger.warn({ programId, err }, 'fetchProgramTraction_fail');
      return { uniqueCallers: 0, isActive: false, deployedAt: null };
    }
  }

  async fetchAchievements(walletAddress: string): Promise<Achievement[]> {
    const cacheKey = `solana:achievements:${walletAddress}`;

    try {
      const cached = await this.redis.get(cacheKey);
      if (cached) {
        return JSON.parse(cached);
      }
    } catch (e) {
      // Ignore cache check errors
    }

    const apiKey = this.config.get<string>('HELIUS_API_KEY');
    if (!apiKey) {
      this.logger.warn('HELIUS_API_KEY is not configured');
      return [];
    }

    try {
      const response = await fetch(
        `https://mainnet.helius-rpc.com/?api-key=${apiKey}`,
        {
          method: 'POST',
          headers: { 'Content-Type': 'application/json' },
          body: JSON.stringify({
            jsonrpc: '2.0',
            id: 'colosseum-1',
            method: 'getAssetsByOwner',
            params: { ownerAddress: walletAddress, page: 1, limit: 1000 },
          }),
        },
      );

      if (!response.ok) {
        throw new Error(`Helius API returned ${response.status}`);
      }

      const data = await response.json();
      const achievements: Achievement[] = [];

      for (const asset of data.result?.items || []) {
        const authority = asset.authorities?.[0]?.address;
        if (!authority) continue;

        const colosseumMatch =
          this.achievementWhitelist.matchColosseum(authority);
        if (colosseumMatch) {
          achievements.push({
            type: 'hackathon_win',
            source: 'colosseum',
            label: colosseumMatch.label,
            year: colosseumMatch.year,
          });
          continue;
        }

        const superteamMatch =
          this.achievementWhitelist.matchSuperteam(authority);
        if (superteamMatch) {
          achievements.push({
            type: 'bounty_completion',
            source: 'superteam',
            label: superteamMatch.label,
            year: superteamMatch.year,
          });
        }
      }

      try {
        await this.redis.set(
          cacheKey,
          JSON.stringify(achievements),
          'EX',
          86400,
        ); // 24h
      } catch (e) {
        // Ignore cache setting errors
      }

      return achievements;
    } catch (err) {
      this.logger.warn(
        { walletAddress, err: (err as Error).message },
        'fetchAchievements_fail',
      );
      return [];
    }
  }

  async fetchOnChainData(walletAddress: string) {
    const [deployedPrograms, achievements] = await Promise.all([
      this.fetchProgramsByAuthority(walletAddress),
      this.fetchAchievements(walletAddress),
    ]);
    return {
      ecosystem: 'solana' as const,
      ecosystemPRs: 0,
      deployedPrograms,
      achievements,
    };
  }
}

import { NestFactory } from '@nestjs/core';
import { AppModule } from '../app.module';
import { GithubAdapterService } from '../scoring/github-adapter/github-adapter.service';
import { ScoringService } from '../scoring/scoring-service/scoring.service';
import { CacheService } from '../scoring/cache/cache.service';
import { Logger } from '@nestjs/common';

const SEED_DEVELOPERS = ['torvalds', 'gaearon', 'yyx990803', 'antirez', 'dhh'];

async function bootstrap() {
  const logger = new Logger('PreloadCache');

  // Disable logging from other modules to keep output clean
  const app = await NestFactory.createApplicationContext(AppModule, {
    logger: ['error', 'warn', 'log'],
  });

  const githubAdapter = app.get(GithubAdapterService);
  const scoringService = app.get(ScoringService);
  const cacheService = app.get(CacheService);

  const token = process.env.GITHUB_TOKEN;
  if (!token) {
    logger.error('GITHUB_TOKEN environment variable is required');
    await app.close();
    process.exit(1);
  }

  logger.log(
    `Starting cache preload for ${SEED_DEVELOPERS.length} developers...`,
  );

  for (const username of SEED_DEVELOPERS) {
    try {
      logger.log(`Processing ${username}...`);

      // 1. Fetch
      const rawData = await githubAdapter.fetchRawData(username, token);

      // 2. Score
      const result = scoringService.score(rawData);

      // 3. Cache
      const cacheKey = cacheService.buildCacheKey(username);
      await cacheService.set(cacheKey, result);

      logger.log(`Successfully preloaded cache for ${username}`);
    } catch (error) {
      logger.error(`Failed to preload ${username}: ${error.message}`);
    }
  }

  logger.log('Preload complete.');
  await app.close();
}

bootstrap();

import * as crypto from 'crypto';

const ALGORITHM = 'aes-256-gcm';
const IV_LENGTH = 12;
const AUTH_TAG_LENGTH = 16;

/**
 * Encrypts a string using AES-256-GCM.
 * The key must be 32 bytes (256 bits).
 */
export function encrypt(text: string, key: string): string {
  if (key.length !== 64) {
    // Expecting hex string of 32 bytes
    throw new Error(
      'Encryption key must be a 64-character hex string (32 bytes)',
    );
  }

  const iv = crypto.randomBytes(IV_LENGTH);
  const cipher = crypto.createCipheriv(ALGORITHM, Buffer.from(key, 'hex'), iv);

  let encrypted = cipher.update(text, 'utf8', 'hex');
  encrypted += cipher.final('hex');

  const authTag = cipher.getAuthTag().toString('hex');

  // Format: iv:authTag:encrypted
  return `${iv.toString('hex')}:${authTag}:${encrypted}`;
}

/**
 * Decrypts a string using AES-256-GCM.
 */
export function decrypt(encryptedData: string, key: string): string {
  if (key.length !== 64) {
    throw new Error(
      'Encryption key must be a 64-character hex string (32 bytes)',
    );
  }

  const [ivHex, authTagHex, encryptedHex] = encryptedData.split(':');

  if (!ivHex || !authTagHex || !encryptedHex) {
    throw new Error('Invalid encrypted data format');
  }

  const iv = Buffer.from(ivHex, 'hex');
  const authTag = Buffer.from(authTagHex, 'hex');
  const decipher = crypto.createDecipheriv(
    ALGORITHM,
    Buffer.from(key, 'hex'),
    iv,
  );

  decipher.setAuthTag(authTag);

  let decrypted = decipher.update(encryptedHex, 'hex', 'utf8');
  decrypted += decipher.final('utf8');

  return decrypted;
}

import { Injectable, Logger } from '@nestjs/common';
import { ConfigService } from '@nestjs/config';
import { Resend } from 'resend';

@Injectable()
export class EmailService {
  private resend: Resend;
  private readonly logger = new Logger(EmailService.name);

  constructor(private configService: ConfigService) {
    const apiKey = this.configService.get<string>('RESEND_API_KEY');
    if (apiKey) {
      this.resend = new Resend(apiKey);
    } else {
      this.logger.warn(
        'RESEND_API_KEY is not defined. Email service will run in stub mode.',
      );
    }
  }

  async sendEmail(to: string, subject: string, html: string) {
    if (!this.resend) {
      this.logger.log(
        `[MAIL STUB] To: ${to}, Subject: ${subject}, Content: ${html}`,
      );
      return;
    }

    try {
      const { data, error } = await this.resend.emails.send({
        from: 'Colosseum <no-reply@colossseum.com>',
        to: [to],
        subject,
        html,
      });

      if (error) {
        this.logger.error(`Failed to send email to ${to}: ${error.message}`);
        throw error;
      }

      this.logger.log(`Email sent to ${to}, ID: ${data?.id}`);
      return data;
    } catch (error) {
      this.logger.error(`Error sending email to ${to}: ${error.message}`);
      throw error;
    }
  }
}

