import { INestApplication } from '@nestjs/common';
import request from 'supertest';
import { resetBefore, resetAfter } from './shared';
import { Test } from '@nestjs/testing';
import { AppModule } from './../src/app.module';
import { PrismaService } from '../src/prisma/prisma.service';
import * as crypto from 'crypto';
import { GithubLinkGuard } from '../src/modules/auth/guards/github.link.guard';
import { MockGithubGuard } from './shared';

describe('Auth Hijacking Prevention (e2e)', () => {
  let app: INestApplication;
  let prisma: PrismaService;
  let id: string;

  beforeEach(async () => {
    const moduleFixture = await Test.createTestingModule({
      imports: [AppModule],
    })
      .overrideGuard(GithubLinkGuard)
      .useClass(MockGithubGuard)
      .compile();

    app = moduleFixture.createNestApplication();
    await app.init();

    prisma = app.get(PrismaService);
    await prisma.$connect();

    id = crypto.randomBytes(16).toString('hex');
  });

  afterEach(async () => {
    await resetAfter(app);
  });

  it('Prevent Account Linking Hijack via predictable state', async () => {
    // 1. Create a "target" user and login
    const targetUser = {
      email: `target-${Date.now()}@example.com`,
      username: `target-${Date.now()}`,
      password: 'Password123!',
      role: 'CANDIDATE',
    };
    await request(app.getHttpServer())
      .post('/auth/register')
      .send(targetUser)
      .expect(201);

    //verify
    await prisma.user.update({
      where: { email: targetUser.email },
      data: { isEmailVerified: true },
    });

    // Assume verification is bypassed or handled for the sake of the test environment setup
    // For this test, we just need a JWT for the target user ID.

    const loginResponse = await request(app.getHttpServer())
      .post('/auth/login')
      .send({
        identifier: targetUser.email,
        password: targetUser.password,
      })
      .expect(201);

    // The account is verified by default in some test setups or we manually update it
    // Let's assume the user is logged in.
    const jwt = loginResponse.body.accessToken;

    // 2. Attacker attempts to link THEIR social account to TARGET'S user ID
    // using a predictable state if the system allowed it.
    // Our fix uses random state in Redis.

    const maliciousCallbackUrl = `/auth/github/link/callback?state=${loginResponse.body.id || 'target_user_id'}`;

    await request(app.getHttpServer())
      .get(maliciousCallbackUrl)
      .set('Authorization', `Bearer ${jwt}`)
      .expect(401);
  });
});

import { INestApplication } from '@nestjs/common';
import request from 'supertest';
import { resetBefore, resetAfter } from './shared';
import { AuthService } from '../src/modules/auth/auth.service';

describe('Auth MFA (e2e)', () => {
  let app: INestApplication;
  let testId: string;
  let accessToken: string;
  let userId: string;

  beforeEach(async () => {
    const setup = await resetBefore();
    app = setup.app;
    testId = setup.id;

    // Register and verify a user for MFA tests
    const email = `mfa-e2e-${testId}@example.com`;
    const regRes = await request(app.getHttpServer())
      .post('/auth/register')
      .send({ email, password: 'StrongPassword123!', role: 'CANDIDATE' })
      .expect(201);

    userId = await setup.prisma.user
      .findUnique({ where: { email } })
      .then((u) => u!.id);
    await setup.prisma.user.update({
      where: { id: userId },
      data: { isEmailVerified: true } as any,
    });

    const loginRes = await request(app.getHttpServer())
      .post('/auth/login')
      .send({ identifier: email, password: 'StrongPassword123!' })
      .expect(201);

    accessToken = loginRes.body.accessToken;
  });

  afterEach(async () => {
    await resetAfter(app);
  });

  it('should complete full MFA lifecycle', async () => {
    // 1. Setup MFA
    const setupRes = await request(app.getHttpServer())
      .get('/auth/mfa/setup')
      .set('Authorization', `Bearer ${accessToken}`)
      .expect(200);

    expect(setupRes.body.qrCode).toBeDefined();
    const secret = setupRes.body.secret;

    // 2. Activate MFA
    const authenticator = (app.get(AuthService) as any).getAuthenticator();
    const code = authenticator.generate(secret);

    const activateRes = await request(app.getHttpServer())
      .post('/auth/mfa/activate')
      .set('Authorization', `Bearer ${accessToken}`)
      .send({ code })
      .expect(201);

    expect(activateRes.body.backupCodes).toHaveLength(10);
    const backupCode = activateRes.body.backupCodes[0];

    // 3. Login with MFA
    const loginRes = await request(app.getHttpServer())
      .post('/auth/login')
      .send({
        identifier: `mfa-e2e-${testId}@example.com`,
        password: 'StrongPassword123!',
      })
      .expect(201);

    expect(loginRes.body.mfaRequired).toBe(true);
    const mfaToken = loginRes.body.mfaToken;

    // 4. Verify MFA
    const verifyCode = authenticator.generate(secret);
    const verifyRes = await request(app.getHttpServer())
      .post('/auth/mfa/verify')
      .send({ code: verifyCode, mfaToken, userId })
      .expect(201);

    expect(verifyRes.body.accessToken).toBeDefined();

    // 5. Recovery with backup code
    const recoveryRes = await request(app.getHttpServer())
      .post('/auth/mfa/verify-recovery')
      .send({ backupCode, mfaToken, userId })
      .expect(201);

    expect(recoveryRes.body.accessToken).toBeDefined();

    // 6. Backup code should be one-time use
    const reuseRes = await request(app.getHttpServer())
      .post('/auth/mfa/verify-recovery')
      .send({ backupCode, mfaToken, userId })
      .expect(401);
  });
});

